$token = "eyJhbGciOiJIUzUxMiJ9..eDwCtbuSaiAusF9RmUsYvFK7C6-lFT0wtAcp9KrsNHvgVt3EX3_-6YUBO2lzpB2b-gWA0Ff0ZVhoXWQvt5g2sQ"

$parts = $token.Split('.')
$payload = $parts[1]
while ($payload.Length % 4 -ne 0) { $payload += "=" }
$bytes = [System.Convert]::FromBase64String($payload)
$json = [System.Text.Encoding]::UTF8.GetString($bytes)
$obj = $json | ConvertFrom-Json

Write-Host "=== Token Payload ===" -ForegroundColor Cyan
Write-Host "Username: $($obj.username)" -ForegroundColor Green
Write-Host "UserId: $($obj.userId)" -ForegroundColor Green
Write-Host "FullName: $($obj.fullName)" -ForegroundColor Green
Write-Host "Email: $($obj.email)" -ForegroundColor Green
Write-Host "Roles: $($obj.roles -join ', ')" -ForegroundColor Green
Write-Host "TenantId: $($obj.tenantId)" -ForegroundColor Green
Write-Host "TokenType: $($obj.tokenType)" -ForegroundColor Green
Write-Host "Issued At: $(Get-Date -UnixTimeSeconds $obj.iat -Format 'yyyy-MM-dd HH:mm:ss')" -ForegroundColor Gray
Write-Host "Expires At: $(Get-Date -UnixTimeSeconds $obj.exp -Format 'yyyy-MM-dd HH:mm:ss')" -ForegroundColor Gray
Write-Host "`nPermissions Count: $($obj.permissions.Count)" -ForegroundColor Yellow
Write-Host "Contains 'exam:view': $($obj.permissions -contains 'exam:view')" -ForegroundColor Yellow

